public class SecureCode {

    private static final String SELECT_QUERY = "SELECT * FROM users WHERE username=? AND password=?";

    public void login(String username, String password) {
        try (Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "root", "password");
             PreparedStatement statement = connection.prepareStatement(SELECT_QUERY)) {

            statement.setString(1, username);
            statement.setString(2, password);

            try (ResultSet resultSet = statement.executeQuery()) {
                if (resultSet.next()) {
                    System.out.println("Login successful!");
                } else {
                    System.out.println("Login failed.");
                }
            }

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        SecureCode code = new SecureCode();
        code.login("admin' OR '1'='1", "password"); // Simulate SQL Injection attempt
    }
}

